"use client";

import * as React from "react";

import { CooperativeChallengeHeader } from "./parts/cooperative-challenge-header";
import { CooperativeChallengeOptIn } from "./parts/cooperative-challenge-optin";
import { CooperativeChallengeProgress } from "./parts/cooperative-challenge-progress";
import { CooperativeChallengeReward } from "./parts/cooperative-challenge-reward";
import { CooperativeChallengeRoot } from "./parts/cooperative-challenge-root";
import type { CooperativeChallengeProps } from "./types";

/**
 * Tier A — the batteries-included assembly: `Root` + `Header` + `Progress` +
 * `Reward?` + `OptIn?`, gated by `show*`. Contains **no logic the parts don't**
 * — a hand-assembled layout (`CooperativeChallengeRoot` + a subset of parts)
 * gets identical derivation, identical controlled-echo, and identical telemetry.
 *
 * A safe-by-design cooperative challenge: one shared team goal, collective
 * progress, a whole-team reward, and a penalty-free opt-in. Never forced, never
 * per-individual, never competitive (system §5).
 */
export function CooperativeChallenge01({
  challenge,
  team,
  onOptInChange,
  onEvent,
  showOptIn = true,
  showReward = true,
  showMemberStack = true,
  joinLabel,
  leaveLabel,
  noPenaltyHint,
  className,
  "aria-label": ariaLabel,
}: CooperativeChallengeProps) {
  return (
    <CooperativeChallengeRoot
      challenge={challenge}
      team={team}
      onOptInChange={onOptInChange}
      onEvent={onEvent}
      joinLabel={joinLabel}
      leaveLabel={leaveLabel}
      noPenaltyHint={noPenaltyHint}
      className={className}
      aria-label={ariaLabel}
    >
      <CooperativeChallengeHeader showMemberStack={showMemberStack} />
      <CooperativeChallengeProgress />
      {showReward ? <CooperativeChallengeReward /> : null}
      {showOptIn ? <CooperativeChallengeOptIn /> : null}
    </CooperativeChallengeRoot>
  );
}

// Tier A — batteries-included assembly.
export { CooperativeChallenge01 } from "./cooperative-challenge-01";

// Tier B — headless provider + flat à-la-carte context parts.
export { CooperativeChallengeRoot } from "./parts/cooperative-challenge-root";
export { CooperativeChallengeHeader } from "./parts/cooperative-challenge-header";
export { CooperativeChallengeProgress } from "./parts/cooperative-challenge-progress";
export { CooperativeChallengeReward } from "./parts/cooperative-challenge-reward";
export { CooperativeChallengeOptIn } from "./parts/cooperative-challenge-optin";

// Tier C — standalone, context-free primitives.
export { ChallengeProgressMeter } from "./parts/cooperative-challenge-progress";
export { ChallengeRewardChip } from "./parts/cooperative-challenge-reward";
export { OptInToggle } from "./parts/cooperative-challenge-optin";
export { TeamMemberStack } from "./parts/team-member-stack";
export { CooperativeChallengeSkeleton } from "./parts/cooperative-challenge-skeleton";

// Context consumer for hand-assembled layouts.
export { useCooperativeChallenge } from "./hooks/use-cooperative-challenge";

// Public types.
export type {
  Challenge,
  Team,
  TeamMember,
  GamificationEvent,
  CooperativeChallengeProps,
  CooperativeChallengeBaseProps,
  CooperativeChallengeRootProps,
  CooperativeChallengeContextValue,
  ChallengeDerived,
  OptInToggleProps,
  ChallengeProgressMeterProps,
  ChallengeRewardChipProps,
  TeamMemberStackProps,
} from "./types";

import type { ReactNode } from "react";

/**
 * `cooperative-challenge-01` — public type surface.
 *
 * Framework-free (no `"use client"`): importable from a server component's type
 * position. Per system D-03 every type this component needs is **re-declared
 * locally** — it imports nothing from another registry component. The
 * `gamification-system` description (§4 domain model, §6 telemetry union) is the
 * source of truth these slices are copied from, not imported. The type
 * duplication across the pack is the accepted price of registry independence
 * (system D-03/D-04); the deferred `gamification-kit` may dedupe later.
 */

/**
 * A member of the owning team — identity only. Renders as an avatar in the
 * `TeamMemberStack`; never a per-member progress/contribution surface (§6.3).
 */
export interface TeamMember {
  id: string;
  displayName: string;
  avatarUrl?: string;
}

/**
 * This team (system D-15). Renders team-identity **text** (the optional header
 * name) → takes a `team` object subset, never a bare `teamId`/`teamName` pair.
 * `id` scopes the telemetry payload; `members` feeds the avatar stack.
 */
export interface Team {
  id: string;
  name: string;
  members: TeamMember[];
}

/**
 * ONE shared team goal (D-C1 — one challenge per component in v1). Progress is a
 * **collective** quantity only (D-C2); the reward is **whole-team** (D-08);
 * opting in is **controlled + never-forced** (D-C3/D-C6).
 */
export interface Challenge {
  id: string;
  /** Header label, e.g. "All 5 members commit a task this morning". Truncated + full text on `title`. */
  label: string;
  /** Controlled, team-level opt-in value (D-C6). Refusing has no penalty. */
  optedIn: boolean;
  /** Collective progress only — never a per-member breakdown (D-C2). */
  progress: { current: number; target: number };
  /** Whole-team reward chip (D-08). Undefined/empty → hidden. */
  reward?: string;
  /** Completed → lightweight inline earned treatment (D-C4). */
  done: boolean;
}

/**
 * The local slice of the system §6 `GamificationEvent` union — **only** the two
 * events this component emits (D-03; a host wiring all six components widens the
 * type at its own telemetry layer). No SDK, no `next/*`.
 */
export type GamificationEvent =
  | { type: "challenge.opened"; teamId: string; challengeId: string }
  | {
      type: "challenge.opt-in";
      teamId: string;
      challengeId: string;
      optedIn: boolean;
    };

/** Data + behavioral surface shared by the assembly and the headless `Root`. */
export interface CooperativeChallengeBaseProps {
  /** The shared team goal to render (one challenge in v1, D-C1). */
  challenge: Challenge;
  /** The team that owns the challenge — name + member stack + scope (D-15). */
  team: Team;
  /** Fires when the team opts in/out (controlled, D-C6). Omit → read-only card (control hides). */
  onOptInChange?: (optedIn: boolean) => void;
  /** Telemetry (system §6, D-07) — emits `challenge.opened` + `challenge.opt-in`. */
  onEvent?: (event: GamificationEvent) => void;
  /** Copy override — the opt-in affordance label. Default `"Join this challenge"`. */
  joinLabel?: string;
  /** Copy override — the opt-out affordance label. Default `"Leave challenge"` (penalty-free). */
  leaveLabel?: string;
  /** Copy override — the cost-free hint. Default `"Optional — no penalty for sitting this one out"`. */
  noPenaltyHint?: string;
}

/** Props for the headless provider `CooperativeChallengeRoot`. */
export interface CooperativeChallengeRootProps
  extends CooperativeChallengeBaseProps {
  children: ReactNode;
  className?: string;
  "aria-label"?: string;
}

/** Props for the batteries-included `CooperativeChallenge01` assembly. */
export interface CooperativeChallengeProps
  extends CooperativeChallengeBaseProps {
  /** Show the opt-in control. Default `true`; `false` → card body only. */
  showOptIn?: boolean;
  /** Show the reward chip. Default `true` (auto-hides if no reward). */
  showReward?: boolean;
  /** Show the member avatar stack. Default `true`. */
  showMemberStack?: boolean;
  className?: string;
  "aria-label"?: string;
}

/** Tier-C context-free bare opt-in toggle (droppable on any surface). */
export interface OptInToggleProps {
  optedIn: boolean;
  onOptInChange?: (optedIn: boolean) => void;
  joinLabel?: string;
  leaveLabel?: string;
  noPenaltyHint?: string;
  disabled?: boolean;
  className?: string;
}

/** Tier-C dumb collective progress meter. */
export interface ChallengeProgressMeterProps {
  current: number;
  target: number;
  /** Earned/complete tint (signal-lime); still collective-only, no per-member surface. */
  complete?: boolean;
  className?: string;
  "aria-label"?: string;
}

/** Tier-C dumb reward chip; `earned` switches framing (available → earned). */
export interface ChallengeRewardChipProps {
  reward: string;
  earned?: boolean;
  className?: string;
}

/** Tier-C dumb avatar pile; `max` caps then `+N`. */
export interface TeamMemberStackProps {
  members: TeamMember[];
  /** Max avatars before a `+N` overflow chip. Default `5`. */
  max?: number;
  className?: string;
}

/** Pure derived state (see `lib/derive.ts`). Deterministic, no clock. */
export interface ChallengeDerived {
  /** Clamped 0..1 fill fraction. */
  progressFraction: number;
  /** `${current} / ${target}` (mono). */
  countLabel: string;
  /** `!optedIn && !done` → neutral, joinable, invitation. */
  isJoinable: boolean;
  /** `optedIn && !done` → active, in-motion. */
  isActive: boolean;
  /** `done` → earned/completed (wins over `optedIn`). */
  isComplete: boolean;
  /** `reward` present + non-empty. */
  hasReward: boolean;
}

/** The value every context part reads — one source of truth. */
export interface CooperativeChallengeContextValue {
  challenge: Challenge;
  team: Team;
  derived: ChallengeDerived;
  /** `true` when the opt-in control should render (a handler is wired). */
  canOptIn: boolean;
  /** Toggle opt-in — computes `next`, calls `onOptInChange`, emits telemetry. */
  toggleOptIn: () => void;
  joinLabel: string;
  leaveLabel: string;
  noPenaltyHint: string;
}

import type { Challenge, ChallengeDerived } from "../types";

/**
 * The pure derivation layer — SSR-deterministic (derives only from the
 * `challenge` prop; never reads `Date`, `Math.random`, layout, or env). Test-
 * ready and a prime candidate to hoist into a shared `gamification-kit` once
 * 2–3 components prove the surface (system §7.3) — keep it standalone.
 *
 * No component-invented progress notion (system D-09 spirit): progress is
 * exactly `challenge.progress`; the card never derives it from milestones.
 */

/** Default never-forced copy — one source of truth for the Root + the bare Tier-C toggle. */
export const DEFAULT_JOIN_LABEL = "Join this challenge";
export const DEFAULT_LEAVE_LABEL = "Leave challenge";
export const DEFAULT_NO_PENALTY_HINT =
  "Optional — no penalty for sitting this one out";

function clamp(n: number, lo: number, hi: number): number {
  return Math.min(Math.max(n, lo), hi);
}

/**
 * Resolve every rendered value from the `challenge`. The `max(target, 1)`
 * divisor avoids NaN/Infinity on the `target === 0` degenerate input (§9); the
 * count label always shows the host's raw `current / target` (never silently
 * rewritten, even when `current > target` — the bar caps at 100%, the count
 * tells the truth).
 */
export function deriveChallenge(challenge: Challenge): ChallengeDerived {
  const { current, target } = challenge.progress;
  const progressFraction = clamp(current / Math.max(target, 1), 0, 1);
  const isComplete = challenge.done;
  const hasReward =
    challenge.reward != null && challenge.reward.trim() !== "";

  return {
    progressFraction,
    countLabel: `${current} / ${target}`,
    // `done` wins over `optedIn` — a completed challenge reads as earned regardless.
    isJoinable: !challenge.optedIn && !isComplete,
    isActive: challenge.optedIn && !isComplete,
    isComplete,
    hasReward,
  };
}

import type { Challenge, GamificationEvent, Team } from "../types";

/**
 * The single place the two event shapes are constructed — standalone pure
 * factories (kit-extraction candidates, system §7.3), so the union stays
 * single-sourced from `types.ts` and the shapes are testable. The host adds the
 * envelope (timestamp, anonymized IDs, app variant) at its transport layer.
 */

/** `challenge.opened` — first reveal/mount of the card (D-C5). */
export function openedEvent(team: Team, challenge: Challenge): GamificationEvent {
  return {
    type: "challenge.opened",
    teamId: team.id,
    challengeId: challenge.id,
  };
}

/** `challenge.opt-in` — the team toggled opt-in; carries the new value. */
export function optInEvent(
  team: Team,
  challenge: Challenge,
  optedIn: boolean,
): GamificationEvent {
  return {
    type: "challenge.opt-in",
    teamId: team.id,
    challengeId: challenge.id,
    optedIn,
  };
}

"use client";

import * as React from "react";

import type { CooperativeChallengeContextValue } from "../types";

export const CooperativeChallengeContext =
  React.createContext<CooperativeChallengeContextValue | null>(null);

/**
 * Read the challenge state from a surrounding `CooperativeChallengeRoot`.
 * For hand-assembled layouts; throws if used outside a `Root`.
 */
export function useCooperativeChallenge(): CooperativeChallengeContextValue {
  const ctx = React.useContext(CooperativeChallengeContext);
  if (ctx === null) {
    throw new Error(
      "useCooperativeChallenge must be used within a <CooperativeChallengeRoot>.",
    );
  }
  return ctx;
}

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import { CooperativeChallengeContext } from "../hooks/use-cooperative-challenge";
import {
  DEFAULT_JOIN_LABEL,
  DEFAULT_LEAVE_LABEL,
  DEFAULT_NO_PENALTY_HINT,
  deriveChallenge,
} from "../lib/derive";
import { openedEvent, optInEvent } from "../lib/events";
import type {
  CooperativeChallengeContextValue,
  CooperativeChallengeRootProps,
} from "../types";

/**
 * Tier B — headless provider. The **single** source of derived state, the
 * **single** controlled-echo chokepoint (reads `challenge.optedIn`, holds no
 * local opt-in state — the rich-card/calendar controlled-echo lesson), and the
 * **single** telemetry chokepoint (`challenge.opened` mount-effect,
 * double-emit-guarded + `challenge.opt-in` on toggle). No layout opinion beyond
 * the labelled region + `reveal-up`; renders `children`.
 */
export function CooperativeChallengeRoot({
  challenge,
  team,
  onOptInChange,
  onEvent,
  joinLabel = DEFAULT_JOIN_LABEL,
  leaveLabel = DEFAULT_LEAVE_LABEL,
  noPenaltyHint = DEFAULT_NO_PENALTY_HINT,
  children,
  className,
  "aria-label": ariaLabel,
}: CooperativeChallengeRootProps) {
  // Latest props read through refs so `toggleOptIn` + the opened-effect stay
  // stable and an inline `onEvent`/`onOptInChange` never re-subscribes anything.
  const challengeRef = React.useRef(challenge);
  const teamRef = React.useRef(team);
  const onOptInChangeRef = React.useRef(onOptInChange);
  const onEventRef = React.useRef(onEvent);
  React.useEffect(() => {
    challengeRef.current = challenge;
    teamRef.current = team;
    onOptInChangeRef.current = onOptInChange;
    onEventRef.current = onEvent;
  });

  const derived = React.useMemo(() => deriveChallenge(challenge), [challenge]);

  // `challenge.opened` — once on first reveal/mount (D-C5). Guard keyed on the
  // challenge id: StrictMode double-invoke + re-renders don't re-fire, but a new
  // challenge mounted into the same Root is correctly a fresh "opened".
  const firedRef = React.useRef<string | null>(null);
  React.useEffect(() => {
    if (firedRef.current === challenge.id) return;
    firedRef.current = challenge.id;
    onEventRef.current?.(openedEvent(teamRef.current, challengeRef.current));
  }, [challenge.id]);

  const toggleOptIn = React.useCallback(() => {
    const next = !challengeRef.current.optedIn;
    // Host callback first (it owns the value + re-renders with the new
    // `challenge.optedIn`), then telemetry — the family's veto-friendly order.
    onOptInChangeRef.current?.(next);
    onEventRef.current?.(
      optInEvent(teamRef.current, challengeRef.current, next),
    );
  }, []);

  const canOptIn = typeof onOptInChange === "function";

  const contextValue = React.useMemo<CooperativeChallengeContextValue>(
    () => ({
      challenge,
      team,
      derived,
      canOptIn,
      toggleOptIn,
      joinLabel,
      leaveLabel,
      noPenaltyHint,
    }),
    [
      challenge,
      team,
      derived,
      canOptIn,
      toggleOptIn,
      joinLabel,
      leaveLabel,
      noPenaltyHint,
    ],
  );

  return (
    <CooperativeChallengeContext.Provider value={contextValue}>
      <div
        role="group"
        aria-label={ariaLabel ?? challenge.label}
        data-state={
          derived.isComplete
            ? "complete"
            : derived.isActive
              ? "active"
              : "joinable"
        }
        className={cn(
          "reveal-up flex w-full flex-col gap-4 rounded-xl border bg-card p-5 text-card-foreground transition-colors",
          // Earned = signal-lime emphasis; active = subtle lime ring; joinable = neutral.
          derived.isComplete
            ? "border-primary/60 bg-primary/5"
            : derived.isActive
              ? "border-primary/40"
              : "border-border",
          className,
        )}
      >
        {children}
      </div>
    </CooperativeChallengeContext.Provider>
  );
}

"use client";

import * as React from "react";
import { CircleCheck } from "lucide-react";

import { Badge } from "@/components/ui/badge";

import { useCooperativeChallenge } from "../hooks/use-cooperative-challenge";
import { TeamMemberStack } from "./team-member-stack";

/**
 * Tier B — the card header: challenge `label` (truncated, full text on `title`)
 * + the state indicator + the optional team name + the `TeamMemberStack`.
 *
 * The state indicator makes opted-out read as *Optional* (an invitation), never
 * *failure* (§6.1). On `done` it becomes the **lightweight inline earned
 * acknowledgement** (§6.4): a "Completed together" pill (glyph + text, not color
 * alone) with a `.reveal-up` micro-entrance (globally reduced-motion-safe) and
 * `aria-live="polite"` so the transition to done is announced once without
 * stealing focus or blocking — the heavy celebration is E6's job, never built
 * here (no modal, no overlay).
 */
export function CooperativeChallengeHeader({
  showMemberStack = true,
}: {
  showMemberStack?: boolean;
}) {
  const { challenge, team, derived } = useCooperativeChallenge();

  const stateIndicator = derived.isComplete ? (
    <span
      className="reveal-up inline-flex items-center gap-1 rounded-4xl bg-primary px-2 py-0.5 text-xs font-medium text-primary-foreground"
    >
      <CircleCheck aria-hidden className="size-3" /> Completed together
    </span>
  ) : derived.isActive ? (
    <Badge variant="secondary">Active</Badge>
  ) : (
    <Badge variant="outline">Optional</Badge>
  );

  return (
    <div className="flex items-start justify-between gap-3">
      <div className="flex min-w-0 flex-col gap-1">
        <div className="flex items-center gap-2" aria-live="polite">
          {stateIndicator}
        </div>
        <h3
          title={challenge.label}
          className="truncate text-sm font-semibold text-foreground"
        >
          {challenge.label}
        </h3>
        {team.name ? (
          <p className="truncate text-xs text-muted-foreground">{team.name}</p>
        ) : null}
      </div>
      {showMemberStack ? (
        <TeamMemberStack members={team.members} className="shrink-0 pt-0.5" />
      ) : null}
    </div>
  );
}

"use client";

import * as React from "react";

import { Progress } from "@/components/ui/progress";
import { cn } from "@/lib/utils";

import { useCooperativeChallenge } from "../hooks/use-cooperative-challenge";
import type { ChallengeProgressMeterProps } from "../types";

function clamp01(current: number, target: number): number {
  return Math.min(Math.max(current / Math.max(target, 1), 0), 1);
}

/**
 * Tier C — dumb **collective** progress meter (system §6.3): ONE bar + ONE
 * `current / target` count (mono). There is deliberately no per-member row,
 * ranking, or "you still need to commit" framing — that would drift toward
 * per-individual tracking (excluded by design). The bar caps at 100%
 * (`clamp01`); the count shows the host's raw truth even past target. AT reads
 * the count via Radix `getValueLabel` (aria-valuetext "3 of 5"), not a bare "%".
 */
export function ChallengeProgressMeter({
  current,
  target,
  complete = false,
  className,
  "aria-label": ariaLabel,
}: ChallengeProgressMeterProps) {
  const pct = Math.round(clamp01(current, target) * 100);

  return (
    <div className={cn("flex flex-col gap-1.5", className)}>
      <Progress
        value={pct}
        max={100}
        getValueLabel={() => `${current} of ${target}`}
        aria-label={ariaLabel ?? `Team progress: ${current} of ${target}`}
        className={cn(
          "h-2.5 bg-muted",
          "motion-reduce:[&_[data-slot=progress-indicator]]:transition-none",
        )}
      />
      <span
        className={cn(
          "font-mono text-xs tabular-nums",
          complete ? "text-primary" : "text-muted-foreground",
        )}
      >
        {current} / {target}
      </span>
    </div>
  );
}

/**
 * Tier B — context wrapper: reads the collective count from context and renders
 * the Tier-C meter. Never a per-member surface.
 */
export function CooperativeChallengeProgress() {
  const { challenge, team, derived } = useCooperativeChallenge();
  return (
    <ChallengeProgressMeter
      current={challenge.progress.current}
      target={challenge.progress.target}
      complete={derived.isComplete}
      aria-label={`${team.name ?? "Team"} progress: ${derived.countLabel}`}
    />
  );
}

"use client";

import * as React from "react";
import { Gift } from "lucide-react";

import { cn } from "@/lib/utils";

import { useCooperativeChallenge } from "../hooks/use-cooperative-challenge";
import type { ChallengeRewardChipProps } from "../types";

/**
 * Tier C — dumb reward chip. Copy frames the reward as the team's **collectively**
 * (system D-08): *"The team earns: …"* (available) → *"The team earned: …"*
 * (`earned`). **Never** first-person ("you'll get") — a first-person framing
 * violates D-08, and there is no per-member reward path in the type system.
 * Token-based (signal-lime on earned via `--primary`), never an ad-hoc green.
 */
export function ChallengeRewardChip({
  reward,
  earned = false,
  className,
}: ChallengeRewardChipProps) {
  return (
    <div
      className={cn(
        "flex items-center gap-2 rounded-lg border px-3 py-2 text-xs",
        earned
          ? "border-primary/40 bg-primary/10 text-foreground"
          : "border-border bg-muted/50 text-muted-foreground",
        className,
      )}
    >
      <Gift
        aria-hidden
        className={cn("size-4 shrink-0", earned && "text-primary")}
      />
      <span className="min-w-0">
        <span className="font-medium text-foreground">
          {earned ? "The team earned:" : "The team earns:"}
        </span>{" "}
        <span className="break-words">{reward}</span>
      </span>
    </div>
  );
}

/**
 * Tier B — context wrapper: reads `reward` + `isComplete`; auto-hides when there
 * is no reward (§5.3). The assembly further gates it with `showReward`.
 */
export function CooperativeChallengeReward() {
  const { challenge, derived } = useCooperativeChallenge();
  if (!derived.hasReward || challenge.reward == null) return null;
  return (
    <ChallengeRewardChip reward={challenge.reward} earned={derived.isComplete} />
  );
}

"use client";

import * as React from "react";

import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

import { useCooperativeChallenge } from "../hooks/use-cooperative-challenge";
import {
  DEFAULT_JOIN_LABEL,
  DEFAULT_LEAVE_LABEL,
  DEFAULT_NO_PENALTY_HINT,
} from "../lib/derive";
import type { OptInToggleProps } from "../types";

/**
 * Tier C — the context-free opt-in **button-toggle** (catalogue C5), droppable
 * on any surface. The never-forced rule made literal (system §5.2):
 *
 *  - **Join** (opted-out) is a *prominent, inviting* primary action — never a
 *    greyed/disabled/failure treatment.
 *  - **Leave** (opted-in) is a *plain, single-click* action — no confirm dialog,
 *    no "are you sure you want to abandon?" guilt, no warning tone. Leaving is
 *    as cost-free as joining.
 *  - The `noPenaltyHint` is visible in **both** states and associated with the
 *    control via `aria-describedby`, so cost-free is explicit in copy, not just
 *    behavior.
 *
 * A labelled button (the visible text carries the copy) reads never-forced far
 * better than a bare `switch` thumb (which implies a "correct" default). State
 * is also conveyed via `aria-pressed`.
 */
export function OptInToggle({
  optedIn,
  onOptInChange,
  joinLabel = DEFAULT_JOIN_LABEL,
  leaveLabel = DEFAULT_LEAVE_LABEL,
  noPenaltyHint = DEFAULT_NO_PENALTY_HINT,
  disabled = false,
  className,
}: OptInToggleProps) {
  const hintId = React.useId();

  return (
    <div className={cn("flex flex-col gap-1.5", className)}>
      <Button
        type="button"
        variant={optedIn ? "outline" : "default"}
        size="sm"
        aria-pressed={optedIn}
        aria-describedby={hintId}
        disabled={disabled}
        onClick={() => onOptInChange?.(!optedIn)}
        className="w-fit"
      >
        {optedIn ? leaveLabel : joinLabel}
      </Button>
      {noPenaltyHint ? (
        <p id={hintId} className="text-xs text-muted-foreground">
          {noPenaltyHint}
        </p>
      ) : null}
    </div>
  );
}

/**
 * Tier B — context wrapper: the opt-in/opt-out control. **Hides entirely** when
 * no `onOptInChange` is wired (capability-gating → a read-only card falls out
 * for free, §6.2). The assembly further gates it with `showOptIn`.
 */
export function CooperativeChallengeOptIn() {
  const { challenge, canOptIn, toggleOptIn, joinLabel, leaveLabel, noPenaltyHint } =
    useCooperativeChallenge();

  if (!canOptIn) return null;

  return (
    <OptInToggle
      optedIn={challenge.optedIn}
      onOptInChange={toggleOptIn}
      joinLabel={joinLabel}
      leaveLabel={leaveLabel}
      noPenaltyHint={noPenaltyHint}
    />
  );
}

"use client";

import * as React from "react";

import {
  Avatar,
  AvatarFallback,
  AvatarGroup,
  AvatarGroupCount,
  AvatarImage,
} from "@/components/ui/avatar";
import { cn } from "@/lib/utils";

import type { TeamMemberStackProps } from "../types";

/** First letters of up to two name words → avatar initials fallback. */
function initials(displayName: string): string {
  const parts = displayName.trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return "?";
  if (parts.length === 1) return parts[0]!.slice(0, 2).toUpperCase();
  return (parts[0]![0]! + parts[parts.length - 1]![0]!).toUpperCase();
}

/**
 * Tier C — dumb avatar pile of `team.members`: image with an initials fallback,
 * `max` (default 5) then a `+N` overflow chip. **Identity only** — this is the
 * ONLY member-level surface (system §6.3); it reinforces *shared goal*, never a
 * per-member progress/contribution display (no per-avatar checkmark/state). The
 * pile is one accessible label ("5 team members"), not N announcements; the
 * avatars themselves are decorative (`aria-hidden`).
 */
export function TeamMemberStack({
  members,
  max = 5,
  className,
}: TeamMemberStackProps) {
  if (members.length === 0) return null;

  const shown = members.slice(0, max);
  const overflow = members.length - shown.length;

  return (
    <div
      role="group"
      aria-label={`${members.length} team ${members.length === 1 ? "member" : "members"}`}
      className={cn("inline-flex", className)}
    >
      <AvatarGroup aria-hidden>
        {shown.map((member) => (
          <Avatar key={member.id}>
            {member.avatarUrl ? (
              <AvatarImage src={member.avatarUrl} alt="" />
            ) : null}
            <AvatarFallback>{initials(member.displayName)}</AvatarFallback>
          </Avatar>
        ))}
        {overflow > 0 ? <AvatarGroupCount>+{overflow}</AvatarGroupCount> : null}
      </AvatarGroup>
    </div>
  );
}

